THRESHOLD_JAW_OPEN = 0.12
THRESHOLD_SMILE = 0.08

# Порядок должен совпадать с model['annotation'] в 3DDFA-V3 (core/3ddfa_v3/model/recon.py):
# [right_eye, left_eye, right_eyebrow, left_eyebrow, nose, up_lip, down_lip, skin]
