# --- Helpers ---
def zone_analysis_role(zone_name: str) -> str:
    return ZONE_CONFIG.get(zone_name, ('unknown', 'unknown', 0.0))[0]

def zone_bone_priority_class(zone_name: str) -> str:
    return ZONE_CONFIG.get(zone_name, ('unknown', 'unknown', 0.0))[1]

def zone_bone_weight(zone_name: str) -> float:
    return ZONE_CONFIG.get(zone_name, ('unknown', 'unknown', 0.0))[2]

def static_zone_schema() -> dict[str, object]:
    zones = []
    for z in BASE_ZONE_NAMES:
        zones.append({
            'name': z,
            'kind': 'base',
            'parent_zone': None,
            'segmentation_source': 'authoritative_annotation_group',
            'split_basis': None,
            'analysis_role': zone_analysis_role(z),
            'bone_priority_class': zone_bone_priority_class(z),
            'bone_weight': zone_bone_weight(z),
            'excluded_from_geometry_analysis': z in EXCLUDED_FROM_ANALYSIS,
        })
    for z in DERIVED_ZONE_NAMES:
        zones.append({
            'name': z,
            'kind': 'derived',
            'parent_zone': 'skin' if 'skin' not in z else None,
            'segmentation_source': 'derived_from_base_zone',
            'split_basis': 'fixed_index_range',
            'analysis_role': zone_analysis_role(z),
            'bone_priority_class': zone_bone_priority_class(z),
            'bone_weight': zone_bone_weight(z),
            'excluded_from_geometry_analysis': z in EXCLUDED_FROM_ANALYSIS,
        })
    return {
        'base_zone_count': len(BASE_ZONE_NAMES),
        'derived_zone_count': len(DERIVED_ZONE_NAMES),
        'total_zone_count': len(BASE_ZONE_NAMES) + len(DERIVED_ZONE_NAMES),
        'derived_zone_names': list(DERIVED_ZONE_NAMES),
        'geometry_excluded_zone_names': sorted(EXCLUDED_FROM_ANALYSIS),
        'zones': zones,
    }

def zone_schema_from_result(result) -> dict[str, object]:
    return static_zone_schema()

# --- Metrics ---

AXIS_NAMES = ("lateral", "vertical", "depth")

POSITIVE_DIRECTION_LABELS = {
    "lateral": "shifted_right",
    "vertical": "shifted_up",
    "depth": "shifted_forward",
}
NEGATIVE_DIRECTION_LABELS = {
    "lateral": "shifted_left",
    "vertical": "shifted_down",
    "depth": "shifted_backward",
}

def _insufficient_zone_metric(name: str, shared_vertex_count: int, view_name: str | None = None) -> ZoneMetric:
    return ZoneMetric(
        name=name,
        status="insufficient_support",
        shared_vertex_count=shared_vertex_count,
        analysis_role=zone_analysis_role(name),
        bone_priority_class=zone_bone_priority_class(name),
        bone_weight=zone_bone_weight(name),
        raw_error=None,
        bounded_score=None,
        mean_weight=None,
        mean_signed_depth_delta=None,
        mean_signed_lateral_delta=None,
        mean_signed_vertical_delta=None,
        principal_shift_axis=None,
        dominant_shift_direction=None,
        view=view_name,
        metric=None,
        delta_mm=None,
        delta_rel=None,
        z_score=None,
        level_1_5=None,
        text_user=None,
        text_expert=None,
    )

def _build_zone_metric(
    name: str,
    zone_shared_positions_np: np.ndarray,
    aligned_points_a: np.ndarray,
    points_b: np.ndarray,
    shared_weights: np.ndarray,
    min_zone_vertices: int,
    view_name: str | None = None,
    face_width: float | None = None,
    plane_normal: np.ndarray | None = None,
) -> ZoneMetric:
    if int(zone_shared_positions_np.size) < min_zone_vertices:
        return _insufficient_zone_metric(name, int(zone_shared_positions_np.size), view_name)

    diffs = aligned_points_a[zone_shared_positions_np] - points_b[zone_shared_positions_np]
    zone_weights = shared_weights[zone_shared_positions_np]

    # Guard against degenerate zone with zero total weight
    weight_sum = float(np.sum(zone_weights))
    if weight_sum <= 1e-8:
        return _insufficient_zone_metric(name, int(zone_shared_positions_np.size), view_name)

    if face_width is None or face_width <= 0:
        face_width = 1.0

    # Основная зональная метрика: нормализованная 3D-норма (как и глобальная)
    distances_3d = np.linalg.norm(diffs, axis=1) / face_width
    raw_error = weighted_mean_abs(distances_3d, zone_weights)

    # Дельты тоже нормализуем, чтобы метрики были сравнимы
    diffs_normalized = diffs / face_width
    mean_signed_lateral_delta = float(np.average(diffs_normalized[:, 0], weights=zone_weights))
    mean_signed_vertical_delta = float(np.average(diffs_normalized[:, 1], weights=zone_weights))
    mean_signed_depth_delta = float(np.average(diffs_normalized[:, 2], weights=zone_weights))

    directional_values = {
        "lateral": mean_signed_lateral_delta,
        "vertical": mean_signed_vertical_delta,
        "depth": mean_signed_depth_delta,
    }
    principal_shift_axis = max(AXIS_NAMES, key=lambda axis_name: abs(directional_values[axis_name]))
    dominant_shift_direction = (
        POSITIVE_DIRECTION_LABELS[principal_shift_axis]
        if directional_values[principal_shift_axis] >= 0.0
        else NEGATIVE_DIRECTION_LABELS[principal_shift_axis]
    )

    # raw_error — безразмерная величина (расстояние / масштаб лица)
    delta_norm = float(raw_error)
    delta_rel = delta_norm
    z_score = delta_norm / 0.05
    
    if z_score < 1.0: level_1_5 = 1
    elif z_score < 2.0: level_1_5 = 2
    elif z_score < 3.0: level_1_5 = 3
    elif z_score < 4.0: level_1_5 = 4
    else: level_1_5 = 5

    level_desc = {
        1: 'различий почти не видно',
        2: 'очень слабое отличие',
        3: 'умеренное отличие',
        4: 'заметное отличие',
        5: 'сильное отличие'
    }
    direction_ru = {
        'shifted_right': 'смещено вправо',
        'shifted_left': 'смещено влево',
        'shifted_up': 'смещено вверх',
        'shifted_down': 'смещено вниз',
        'shifted_forward': 'выступает сильнее',
        'shifted_backward': 'более плоское/утопленное'
    }
    dir_str = direction_ru.get(dominant_shift_direction, '')
    
    desc_str = level_desc[level_1_5].capitalize()
    text_user = f"{desc_str} ({level_1_5}/5): {dir_str}."
    text_expert = f"Δnorm={delta_norm:.4f}, rel={delta_rel*100:.1f}%, z={z_score:.2f}."

    return ZoneMetric(
        name=name,
        status="ok",
        shared_vertex_count=int(zone_shared_positions_np.size),
        analysis_role=zone_analysis_role(name),
        bone_priority_class=zone_bone_priority_class(name),
        bone_weight=zone_bone_weight(name),
        raw_error=float(raw_error),
        bounded_score=bounded_score_from_error(float(raw_error)),
        mean_weight=float(np.mean(zone_weights)),
        mean_signed_depth_delta=mean_signed_depth_delta,
        mean_signed_lateral_delta=mean_signed_lateral_delta,
        mean_signed_vertical_delta=mean_signed_vertical_delta,
        principal_shift_axis=principal_shift_axis,
        dominant_shift_direction=dominant_shift_direction,
        view=view_name,
        metric=principal_shift_axis,
        delta_mm=None,
        delta_rel=delta_rel,
        z_score=z_score,
        level_1_5=level_1_5,
        text_user=text_user,
        text_expert=text_expert,
    )


def compute_zone_metrics(
    reconstruction_a: ReconstructionResult,
    reconstruction_b: ReconstructionResult,
    shared_indices: np.ndarray,
    aligned_points_a: np.ndarray,
    points_b: np.ndarray,
    shared_weights: np.ndarray,
    min_zone_vertices: int,
    view_name: str | None = None,
    plane_normal: np.ndarray | None = None,
) -> list[ZoneMetric]:
    shared_lookup = {int(vertex_id): idx for idx, vertex_id in enumerate(shared_indices.tolist())}
    zones: list[ZoneMetric] = []
    
    x_coords = points_b[:, 0]
    face_width = float(np.max(x_coords) - np.min(x_coords))

    # 1) Базовые зоны аннотаций (губы исключены — сильно зависят от мимики)
    for zone_name, zone_vertices in zip(BASE_ZONE_NAMES, reconstruction_a.annotation_groups):
        if zone_name in EXCLUDED_FROM_ANALYSIS:
            continue
        zone_shared_positions = [
            shared_lookup[int(vertex_id)]
            for vertex_id in zone_vertices.tolist()
            if int(vertex_id) in shared_lookup
        ]
        zone_shared_positions_np = np.asarray(zone_shared_positions, dtype=np.int64)
        zones.append(
            _build_zone_metric(
                name=zone_name,
                zone_shared_positions_np=zone_shared_positions_np,
                aligned_points_a=aligned_points_a,
                points_b=points_b,
                shared_weights=shared_weights,
                min_zone_vertices=min_zone_vertices,
                view_name=view_name,
                face_width=face_width,
                plane_normal=plane_normal,
            )
        )

    # 2) Макро-зоны из ТЗ
    for macro_name, indices in MACRO_BONE_INDICES.items():
        if macro_name in EXCLUDED_FROM_ANALYSIS:
            continue
        if not indices or macro_name == 'full_mesh':
             if macro_name == 'full_mesh':
                 zone_shared_positions_np = np.arange(len(shared_indices), dtype=np.int64)
             else:
                 zone_shared_positions_np = np.empty((0,), dtype=np.int64)
        else:
            all_vertices = list(indices)
            zone_shared_positions = [
                shared_lookup[int(vertex_id)]
                for vertex_id in all_vertices
                if int(vertex_id) in shared_lookup
            ]
            zone_shared_positions_np = np.asarray(zone_shared_positions, dtype=np.int64)
            
        zones.append(
            _build_zone_metric(
                name=macro_name,
                zone_shared_positions_np=zone_shared_positions_np,
                aligned_points_a=aligned_points_a,
                points_b=points_b,
                shared_weights=shared_weights,
                min_zone_vertices=min_zone_vertices,
                view_name=view_name,
                face_width=face_width,
                plane_normal=plane_normal,
            )
        )
        
    return zones

def summarize_bone_priority_metrics(zones: list[ZoneMetric], min_usable_bone_zones: int) -> dict[str, object]:
    bone_zones = [z for z in zones if z.bone_priority_class in ("bone_priority_core", "bone_priority_supporting")]
    if not bone_zones:
        return {
            "bone_raw_geometry_error": None,
            "bone_bounded_similarity_score": None,
            "bone_zone_count_total": 0,
            "bone_zone_count_usable": 0,
            "bone_zone_count_core_usable": 0,
            "bone_zone_count_supporting_usable": 0,
            "bone_zone_coverage_quality": "insufficient",
            "bone_zone_weight_total": 0.0,
            "bone_priority_zone_weights": {},
            "top_bone_priority_zones": [],
            "bone_anomalies": [],
            "soft_tissue_anomalies": [],
            "potential_silicone_mask": False,
            "inflation_detected_zones": [],
        }

    usable_bone_zones = [z for z in bone_zones if z.status == "ok" and z.raw_error is not None]
    core_usable = [z for z in usable_bone_zones if z.bone_priority_class == "bone_priority_core"]
    supporting_usable = [z for z in usable_bone_zones if z.bone_priority_class == "bone_priority_supporting"]

    quality = "insufficient"
    if len(usable_bone_zones) >= min_usable_bone_zones:
        quality = "sufficient"
        if len(core_usable) >= 3 and len(supporting_usable) >= 2:
            quality = "robust"

    weight_total = sum(z.bone_weight for z in usable_bone_zones)
    bone_raw_geom_error = None
    bone_bounded_score = None
    if weight_total > 1e-6:
        bone_raw_geom_error = sum((z.raw_error or 0.0) * z.bone_weight for z in usable_bone_zones) / weight_total
        bone_bounded_score = sum((z.bounded_score or 0.0) * z.bone_weight for z in usable_bone_zones) / weight_total

    zone_weights = {z.name: z.bone_weight for z in bone_zones}
    top_zones = [z.name for z in sorted(bone_zones, key=lambda z: z.bone_weight, reverse=True)]

    return {
        "bone_raw_geometry_error": float(bone_raw_geom_error) if bone_raw_geom_error is not None else None,
        "bone_bounded_similarity_score": float(bone_bounded_score) if bone_bounded_score is not None else None,
        "bone_zone_count_total": len(bone_zones),
        "bone_zone_count_usable": len(usable_bone_zones),
        "bone_zone_count_core_usable": len(core_usable),
        "bone_zone_count_supporting_usable": len(supporting_usable),
        "bone_zone_coverage_quality": quality,
        "bone_zone_weight_total": float(weight_total),
        "bone_priority_zone_weights": zone_weights,
        "top_bone_priority_zones": top_zones,
        "bone_anomalies": [],
        "soft_tissue_anomalies": [],
        "potential_silicone_mask": False,
        "inflation_detected_zones": [],
    }

def calculate_z_depth_orbitals(vertices_centered: np.ndarray) -> float:
    """
    [FORENSIC-01] Z-Анализ глубины глазниц.
    Вычисляет среднее углубление (ось Z) глазниц относительно кончика переносицы.
    (Силиконовая маска уменьшает физическую глубину из-за толщины материала).
    """
    # Предполагается, что вершины уже нормализованы (GPA из Части 1).
    nasion_indices = list(MACRO_BONE_INDICES.get('nose_bridge_tip', []))
    eye_indices = list(MACRO_BONE_INDICES.get('orbit_L', frozenset())) + list(MACRO_BONE_INDICES.get('orbit_R', frozenset()))
    
    if len(nasion_indices) == 0 or len(eye_indices) == 0:
        return 0.0

    nasion_z = np.mean(vertices_centered[nasion_indices, 2])
    eyes_z = np.mean(vertices_centered[eye_indices, 2])
    
    # Дистанция по оси глубины (камеры)
    depth = nasion_z - eyes_z
    return float(depth)


def calculate_mirror_asymmetry(vertices_canonical: np.ndarray, shared_indices: np.ndarray) -> float:
    """
    [FORENSIC-03] Mirror Procrustes (Вектор зеркальной асимметрии).
    Ищет неестественные перекосы (когда маска надета криво).
    """
    if len(shared_indices) == 0:
        return 0.0

    # Создаем зеркальное отражение лица по оси X
    mirrored = vertices_canonical.copy()
    mirrored[:, 0] = -mirrored[:, 0]
    
    # Пытаемся наложить отраженное лицо на оригинальное
    alignment = rigid_umeyama(
        mirrored[shared_indices], 
        vertices_canonical[shared_indices], 
        allow_scale=False
    )
    
    # Residual error показывает уровень природной/искусственной асимметрии
    return float(alignment.residual_after)

def calculate_jaw_width(vertices_centered: np.ndarray) -> float:
    """
    [FORENSIC-02] Вычисляет расстояние между углами челюсти (jaw_L и jaw_R).
    Силиконовая маска может расширять лицо в этой области.
    """
    jaw_L_indices = list(MACRO_BONE_INDICES.get('jaw_L', []))
    jaw_R_indices = list(MACRO_BONE_INDICES.get('jaw_R', []))
    
    if len(jaw_L_indices) == 0 or len(jaw_R_indices) == 0:
        return 0.0
        
    jaw_L_pt = np.mean(vertices_centered[jaw_L_indices], axis=0)
    jaw_R_pt = np.mean(vertices_centered[jaw_R_indices], axis=0)
    
    width = np.linalg.norm(jaw_L_pt - jaw_R_pt)
    return float(width)
